const KEYS = ["enabled", "youtube", "facebook"];

async function loadSettings() {
  const settings = await chrome.storage.sync.get(KEYS);

  for (const key of KEYS) {
    const input = document.getElementById(key);
    if (!input) continue;
    input.checked = settings[key] !== false;
  }
}

async function saveSetting(key, value) {
  await chrome.storage.sync.set({ [key]: value });
}

function wireEvents() {
  for (const key of KEYS) {
    const input = document.getElementById(key);
    if (!input) continue;
    input.addEventListener("change", () => {
      saveSetting(key, input.checked);
    });
  }
}

loadSettings();
wireEvents();
EOF"}

{"cmd":"cat > content.js <<'EOF'
const DEFAULT_SETTINGS = {
  enabled: true,
  youtube: true,
  facebook: true,
  delayMs: 700,
};

let settings = { ...DEFAULT_SETTINGS };
let currentVideo = null;

const wait = (ms) => new Promise((resolve) => setTimeout(resolve, ms));

function isYouTubeShorts() {
  const host = window.location.hostname;
  const path = window.location.pathname;
  return /(^|\.)youtube\.com$/.test(host) && path.startsWith("/shorts/");
}

function isFacebookReels() {
  const host = window.location.hostname;
  const path = window.location.pathname;
  return /(^|\.)facebook\.com$/.test(host) && (path.includes("/reel/") || path.includes("/watch/"));
}

function canRunOnCurrentPage() {
  if (!settings.enabled) return false;
  if (isYouTubeShorts()) return settings.youtube;
  if (isFacebookReels()) return settings.facebook;
  return false;
}

function dispatchKey(key) {
  const target = document.activeElement || document.body;
  const keydown = new KeyboardEvent("keydown", { key, bubbles: true, cancelable: true });
  const keyup = new KeyboardEvent("keyup", { key, bubbles: true, cancelable: true });
  target.dispatchEvent(keydown);
  target.dispatchEvent(keyup);
}

function clickFirstVisible(selectors) {
  for (const selector of selectors) {
    const node = document.querySelector(selector);
    if (!node) continue;
    if (!(node instanceof HTMLElement)) continue;
    if (node.offsetParent === null) continue;
    node.click();
    return true;
  }
  return false;
}

function clickButtonByLabelRegex(regex) {
  const buttons = Array.from(document.querySelectorAll("button,[role='button']"));
  const match = buttons.find((el) => {
    if (!(el instanceof HTMLElement)) return false;
    if (el.offsetParent === null) return false;

    const label = [
      el.getAttribute("aria-label") || "",
      el.getAttribute("title") || "",
      el.textContent || "",
    ]
      .join(" ")
      .trim();

    return regex.test(label);
  });

  if (!match) return false;
  match.click();
  return true;
}

async function goToNextShort() {
  if (isYouTubeShorts()) {
    const bySelector = clickFirstVisible([
      "#navigation-button-down button",
      "ytd-shorts ytd-button-renderer#button button",
      "button[aria-label*='Next']",
      "button[title*='Next']",
    ]);

    if (!bySelector) {
      const byLabel = clickButtonByLabelRegex(/next|tiep|tiếp|sau/i);
      if (!byLabel) {
        dispatchKey("ArrowDown");
        dispatchKey("PageDown");
      }
    }
    return;
  }

  if (isFacebookReels()) {
    const bySelector = clickFirstVisible([
      "div[aria-label*='Next']",
      "button[aria-label*='Next']",
      "[data-testid='next_button']",
    ]);

    if (!bySelector) {
      const byLabel = clickButtonByLabelRegex(/next|tiep|tiếp|sau/i);
      if (!byLabel) {
        dispatchKey("ArrowDown");
        dispatchKey("PageDown");
        window.scrollBy({ top: window.innerHeight * 0.9, behavior: "smooth" });
      }
    }
  }
}

async function onVideoEnded() {
  if (!canRunOnCurrentPage()) return;
  await wait(settings.delayMs);
  await goToNextShort();
}

function bindVideo(video) {
  if (!(video instanceof HTMLVideoElement)) return;
  if (video === currentVideo) return;

  if (currentVideo) {
    currentVideo.removeEventListener("ended", onVideoEnded);
  }

  currentVideo = video;
  currentVideo.addEventListener("ended", onVideoEnded);
}

function scanAndBindVideo() {
  if (!canRunOnCurrentPage()) return;
  const videos = Array.from(document.querySelectorAll("video"));
  if (videos.length === 0) return;

  const active = videos.find((v) => !v.paused && v.readyState > 1) || videos[0];
  bindVideo(active);
}

async function loadSettings() {
  const stored = await chrome.storage.sync.get(Object.keys(DEFAULT_SETTINGS));
  settings = { ...DEFAULT_SETTINGS, ...stored };
}

function watchStorage() {
  chrome.storage.onChanged.addListener((changes, area) => {
    if (area !== "sync") return;
    for (const key of Object.keys(DEFAULT_SETTINGS)) {
      if (changes[key]) {
        settings[key] = changes[key].newValue;
      }
    }
  });
}

function initObservers() {
  const observer = new MutationObserver(() => {
    scanAndBindVideo();
  });

  observer.observe(document.documentElement, {
    childList: true,
    subtree: true,
  });

  window.addEventListener("popstate", scanAndBindVideo);
  document.addEventListener("visibilitychange", () => {
    if (!document.hidden) scanAndBindVideo();
  });

  setInterval(scanAndBindVideo, 1500);
}

(async function init() {
  await loadSettings();
  watchStorage();
  scanAndBindVideo();
  initObservers();
})();
EOF"}

